<template>
  <div>
    <el-form ref="form" :model="form" class="box-set" label-width="120px">
      <el-card header="基礎訊息" shadow="naver">
        <el-form-item label="活動封麵">
          <div class="frm-tips">只能上傳jpg/png文件，且不超過2M （建議尺寸：400px * 450px）</div>
          <div>
            <imgBox :img-url="wximageurl + form.ad_pic" inline @click="handleImgChange" />
          </div>
          <imgPicker
            :dialog-visible="imgDialog"
            :sc-status="isGetImage"
            @chooseImg="pickImg"
            @closeImgDialog="closeImgDialog"
          />
        </el-form-item>
        <el-form-item label="活動名稱" required>
          <el-col :span="20">
            <el-input v-model="form.marketing_name" placeholder="活動名稱" />
          </el-col>
        </el-form-item>
        <el-form-item label="延期期限" required>
          <el-col :span="20">
            <el-input v-model="form.prolong_month" style="width: 120px" :disabled="form.status == 'waiting' ? false : true"/>&nbsp;&nbsp;月
          </el-col>
        </el-form-item>
        <el-form-item label="活動時間" required>
          <el-col :span="20">
            <el-date-picker
              v-model="activity_date"
              type="datetimerange"
              range-separator="至"
              start-placeholder="生效時間"
              end-placeholder="過期時間"
              value-format="yyyy-MM-dd HH:mm:ss"
              :default-time="['00:00:00', '23:59:59']"
              :disabled="form.status == 'waiting' ? false : true"
            />
          </el-col>
        </el-form-item>
        <el-form-item label="商品有效期" required>
          <el-col :span="20">
            <el-date-picker
              v-model="commodity_effective_date"
              type="datetimerange"
              range-separator="至"
              start-placeholder="開始時間"
              end-placeholder="結束時間"
              value-format="yyyy-MM-dd HH:mm:ss"
              :default-time="['00:00:00', '23:59:59']"
              :disabled="form.status == 'waiting' ? false : true"
            />
          </el-col>
        </el-form-item>
        <el-form-item label="規則描述" required>
          <el-col :span="20">
            <el-input v-model="form.marketing_desc" type="textarea" :rows="2" placeholder=""/>
          </el-col>
        </el-form-item>
      </el-card>
      <el-card header="綁定商品" shadow="naver">
        <el-form-item label="活動商品" required>
          <div>
            <SkuSelector :data="relItems" @change="getItems" :single="true" />
          </div>
        </el-form-item>
      </el-card>
      <el-card header="設置商品" shadow="naver">
        <el-table v-if="form.items.length > 0" :data="form.items" style="line-height: normal;">
          <el-table-column label="ID" prop="item_id" width="60" />
          <el-table-column label="名稱" prop="item_title" />
          <el-table-column label="規格" prop="item_spec_desc" />
          <el-table-column label="活動庫存" width="90">
            <template slot-scope="scope">
              <el-input v-model="scope.row.act_store" :disabled="form.status == 'waiting' ? false : true" width="90" size="mini" />
            </template>
          </el-table-column>
          <el-table-column label="價格區間" width="600">
            <template slot-scope="scope">
              <div>
                <div
                  v-for="(item, key) in scope.row.condition_value"
                  :key="key"
                  class="content-padded"
                >
                  購買
                  <el-input
                    v-model="item.min"
                    :disabled="form.status == 'waiting' && key != 0 ? false : true"
                    type="input"
                    placeholder="整數數字"
                    style="width: 100px"
                    size="mini"
                  />
                  ~
                  <el-input
                    v-model="item.max"
                    :disabled="form.status == 'waiting' ? false : true"
                    type="input"
                    placeholder="整數數字"
                    style="width: 100px"
                    size="mini"
                  />
                  件，單件
                  <el-input
                    v-model="item.act_price"
                    :disabled="form.status == 'waiting' ? false : true"
                    type="input"
                    placeholder="例:10"
                    style="width: 100px"
                    size="mini"
                  />
                  台幣 &nbsp;&nbsp;<i
                    v-if="key != 0 && form.status == 'waiting'"
                    class="iconfont icon-trash-alt"
                    @click="delRules(scope.$index, key)"
                  />
                </div>
                <div>
                  <el-button
                    :disabled="form.status == 'waiting' ? false : true"
                    type="primary"
                    size="mini"
                    @click="addRules(scope.$index)"
                  >
                    新增區間
                  </el-button>
                </div>
              </div>
            </template>
          </el-table-column>
        </el-table>
      </el-card>

      <div class="content-center">
        <el-button @click.native="handleCancel"> 返回 </el-button>
        <el-button type="primary" @click="submitActivityAction()"> 儲存 </el-button>
      </div>
    </el-form>
  </div>
</template>

<script>
import {
  addtMultibuyActivity,
  updatetMultibuyActivity,
  getMultibuyActivityInfo
} from '../../../../api/promotions'
import SkuSelector from '@/components/function/skuSelector'
import imgPicker from '@/components/imageselect'
import imgBox from '@/components/element/imgBox'

export default {
  inject: ['refresh'],
  components: {
    SkuSelector,
    imgPicker,
    imgBox
  },
  data() {
    return {
      cursymbol: 'NT$',
      community: '1',
      relItems: [],
      addedItems: [],
      form: {
        marketing_type: 'multi_buy',
        marketing_name: '',
        marketing_desc: '',
        start_time: '',
        end_time: '',
        items: [],
        ad_pic: '',
        prolong_month: '',
        status: 'waiting',

        //商品有效期
        commodity_effective_start_time: '',
        commodity_effective_end_time: '',
      },
      activity_date: '',
      commodity_effective_date: '',
      imgDialog: false,
      isGetImage: false
    }
  },
  mounted() {
    if (this.$route.params.marketing_id) {
      this.getActivityDetail(this.$route.params.marketing_id)
    }
  },
  methods: {
    getItems(data) {
      console.log('getItems', data)
      let arr = []
      data.forEach((item, index) => {
        let newData = ''
        let isInArr = this.addedItems.findIndex((n) => n.item_id == item.itemId)
        if (isInArr == -1) {
          newData = {
            item_id: item.itemId,
            item_title: item.itemName,
            item_spec_desc: item.item_spec_desc,
            act_store: item.store,
            condition_value: [{ min: 1, max: null, act_price: null }]
          }
        } else {
          newData = this.addedItems[index]
        }
        arr.push(newData)
      })
      this.form.items = arr
    },
    handleImgChange() {
      this.imgDialog = true
      this.isGetImage = true
    },
    pickImg(data) {
      this.form.ad_pic = data.url
      this.imgDialog = false
    },
    closeImgDialog() {
      this.imgDialog = false
    },
    submitActivityAction() {
      const that = this
      if (!this.form.marketing_name) {
        this.$message.error('請填寫活動名稱!')
        return
      }
      if (!this.form.prolong_month) {
        this.$message.error('請填寫延期期限!')
        return
      }
      if (this.activity_date.length > 0) {
        this.form.start_time = this.activity_date[0]
        this.form.end_time = this.activity_date[1]
      } else {
        this.$message.error('請填寫活動時間!')
        return
      }
      if (this.commodity_effective_date.length > 0) {
        this.form.commodity_effective_start_time = this.commodity_effective_date[0]
        this.form.commodity_effective_end_time = this.commodity_effective_date[1]
      } else {
        this.$message.error('請填寫商品有效期!')
        return
      }
      if (!this.form.marketing_desc) {
        this.$message.error('請填規則描述!')
        return
      }
      if (!this.form.items.length) {
        this.$message.error('請選擇團商品!')
        return
      }
      if (this.form.marketing_id) {
        updatetMultibuyActivity(this.form).then((res) => {
          this.$message({
            message: '更新成功',
            type: 'success',
            duration: 2 * 1000,
            onClose() {
              that.refresh()
              that.$router.go(-1)
            }
          })
        })
      } else {
        addtMultibuyActivity(this.form).then((res) => {
          this.$message({
            message: '新增成功',
            type: 'success',
            duration: 2 * 1000,
            onClose() {
              that.refresh()
              that.$router.go(-1)
            }
          })
        })
      }
    },
    getActivityDetail(id) {
      getMultibuyActivityInfo({ marketing_id: id }).then((res) => {
        let response = res.data.data
        console.log(response)
        let data = {
          marketing_id: response.marketing_id,
          marketing_type: 'multi_buy',
          marketing_name: response.marketing_name,
          marketing_desc: response.marketing_desc,
          start_time: response.start_time,
          end_time: response.end_time,
          commodity_effective_start_time: response.commodity_effective_start_time,
          commodity_effective_end_time: response.commodity_effective_end_time,
          items: [],
          ad_pic: response.ad_pic,
          prolong_month: response.prolong_month,
          status: response.status
        }
        Object.assign(this.form, data)
        this.addedItems = response.condition_list
        this.activity_date = [response.start_time, response.end_time];
        this.commodity_effective_date = [response.commodity_effective_end_time, response.commodity_effective_end_time];
        this.relItems = response.itemTreeLists || []
      })
    },
    handleCancel: function () {
      this.$router.go(-1)
    },
    addRules(parentIndex) {
      this.form.items[parentIndex].condition_value.push({ min: '', max: '', act_price: '' })
    },
    delRules(parentIndex, index) {
      this.form.items[parentIndex].condition_value.splice(index, 1)
    }
  }
}
</script>
